def correct_bracketing(brackets: str):
    """ brackets is a string of "(" and ")".
    return True if every opening bracket has a corresponding closing bracket.

    >>> correct_bracketing("(")
    False
    >>> correct_bracketing("()")
    True
    >>> correct_bracketing("(()())")
    True
    >>> correct_bracketing(")(()")
    False
    """
    count_brackets = {}  # dict of {open_brackets: close_brackets}

    for c in brackets:
        if c == "(" or c == ")":
            # check if this is a closing bracket
            if count_brackets.get(c) is None:
                count_brackets[c] = 1  # first time seeing this bracket type
            else:
                count_brackets[c] += 1  # seen this bracket type before, add a count
                if count_brackets[c] > 1:  # seen this bracket type more than 1 time, not balanced
                    return False
    return count_brackets.get("(") == count_brackets.get(")")

