def starts_one_ends(n):
    """
    Given a positive integer n, return the count of the numbers of n-digit
    positive integers that start or end with 1.
    """
    def starts_or_ends(n):
        if n < 10:
            return 10
        elif n < 100:
            return 9*pow(10, n - 10)
        elif n < 1000:
            return 9*pow(10, n - 10) + starts_or_ends(n-1)
        else:
            raise OverflowError
    return starts_or_ends(n)

